using Dapper;
using Valora.Application.Contracts;
using Valora.Application.DTOs;

namespace Valora.Infrastructure.Repositories;
public sealed class ModuleRepository(IDbConnectionFactory f):IModuleRepository{ public async Task<IReadOnlyList<ModuleDto>> ListAsync(){using var c=f.Create(); return (await c.QueryAsync<ModuleDto>("SELECT id,code,name,description,category,status,display_order AS DisplayOrder,minimum_plan_code AS MinimumPlanCode FROM valorapesquisa.modules WHERE is_deleted=false ORDER BY display_order,name")).ToList();} public async Task<IReadOnlyList<ModuleDto>> ListForOrganizationAsync(Guid organizationId){using var c=f.Create(); return (await c.QueryAsync<ModuleDto>(@"SELECT m.id,m.code,m.name,m.description,m.category,CASE WHEN COALESCE(om.enabled,true) THEN m.status ELSE 'disabled' END status,m.display_order AS DisplayOrder,m.minimum_plan_code AS MinimumPlanCode FROM valorapesquisa.modules m LEFT JOIN valorapesquisa.organization_modules om ON om.module_id=m.id AND om.organization_id=@organizationId WHERE m.is_deleted=false ORDER BY m.display_order,m.name",new{organizationId})).ToList();} public async Task SetOrganizationModuleAsync(Guid organizationId,string moduleCode,bool enabled){using var c=f.Create(); await c.ExecuteAsync(@"INSERT INTO valorapesquisa.organization_modules(organization_id,module_id,enabled) SELECT @organizationId,id,@enabled FROM valorapesquisa.modules WHERE code=@moduleCode ON CONFLICT (organization_id,module_id) DO UPDATE SET enabled=EXCLUDED.enabled,updated_at=now()",new{organizationId,moduleCode,enabled});}}
public sealed class SubscriptionRepository(IDbConnectionFactory f):ISubscriptionRepository{ public async Task<SubscriptionDto?> GetByOrganizationAsync(Guid organizationId){using var c=f.Create(); return await c.QueryFirstOrDefaultAsync<SubscriptionDto>("SELECT id,organization_id AS OrganizationId,plan_id AS PlanId,status,billing_status AS BillingStatus,starts_at AS StartsAt,expires_at AS ExpiresAt FROM valorapesquisa.subscriptions WHERE organization_id=@organizationId AND is_deleted=false ORDER BY created_at DESC LIMIT 1",new{organizationId});} public async Task UpsertAsync(SubscriptionDto s){using var c=f.Create(); await c.ExecuteAsync(@"INSERT INTO valorapesquisa.subscriptions(id,organization_id,plan_id,status,billing_status,starts_at,expires_at) VALUES(@Id,@OrganizationId,@PlanId,@Status,@BillingStatus,@StartsAt,@ExpiresAt) ON CONFLICT (organization_id) DO UPDATE SET plan_id=EXCLUDED.plan_id,status=EXCLUDED.status,billing_status=EXCLUDED.billing_status,expires_at=EXCLUDED.expires_at,updated_at=now()",s);} public async Task SetStatusAsync(Guid organizationId,string status){using var c=f.Create(); await c.ExecuteAsync("UPDATE valorapesquisa.subscriptions SET status=@status,updated_at=now() WHERE organization_id=@organizationId",new{organizationId,status});}}
public sealed class UsageRepository(IDbConnectionFactory f):IUsageRepository{ public async Task<UsageDto> GetMonthlyAsync(Guid organizationId,DateTime month){using var c=f.Create(); var row=await c.QueryFirstOrDefaultAsync<dynamic>("SELECT active_surveys,responses_count,managers_count FROM valorapesquisa.usage_monthly WHERE organization_id=@organizationId AND month=@month::date",new{organizationId,month=new DateTime(month.Year,month.Month,1)}); return new UsageDto((int?)row?.active_surveys??0,(int?)row?.responses_count??0,(int?)row?.managers_count??0,new Dictionary<string,int>());} public async Task RecalculateAsync(Guid organizationId,DateTime month){using var c=f.Create(); await c.ExecuteAsync(@"INSERT INTO valorapesquisa.usage_monthly(organization_id,month,active_surveys,responses_count,managers_count) VALUES(@organizationId,@month::date,(SELECT count(*) FROM valorapesquisa.surveys WHERE organization_id=@organizationId AND status='active'),(SELECT count(*) FROM valorapesquisa.responses WHERE organization_id=@organizationId AND created_at >= @month::date),(SELECT count(*) FROM valorapesquisa.users WHERE organization_id=@organizationId AND role LIKE '%admin%')) ON CONFLICT (organization_id,month) DO UPDATE SET active_surveys=EXCLUDED.active_surveys,responses_count=EXCLUDED.responses_count,managers_count=EXCLUDED.managers_count,updated_at=now()",new{organizationId,month=new DateTime(month.Year,month.Month,1)});}}
public sealed class DashboardMetricsRepository(IDbConnectionFactory f):IDashboardMetricsRepository{ public async Task<DashboardMetricsDto> GetGlobalAsync(){using var c=f.Create(); return await c.QueryFirstAsync<DashboardMetricsDto>("SELECT (SELECT count(*) FROM valorapesquisa.organizations)::int Organizations,(SELECT count(*) FROM valorapesquisa.users)::int Users,(SELECT count(*) FROM valorapesquisa.surveys)::int Surveys,(SELECT count(*) FROM valorapesquisa.responses)::int Responses,(SELECT count(*) FROM valorapesquisa.subscriptions WHERE status='active')::int ActiveSubscriptions");} public async Task<DashboardMetricsDto> GetOrganizationAsync(Guid organizationId){using var c=f.Create(); return await c.QueryFirstAsync<DashboardMetricsDto>("SELECT 1 Organizations,(SELECT count(*) FROM valorapesquisa.users WHERE organization_id=@organizationId)::int Users,(SELECT count(*) FROM valorapesquisa.surveys WHERE organization_id=@organizationId)::int Surveys,(SELECT count(*) FROM valorapesquisa.responses WHERE organization_id=@organizationId)::int Responses,(SELECT count(*) FROM valorapesquisa.subscriptions WHERE organization_id=@organizationId AND status='active')::int ActiveSubscriptions",new{organizationId});}}
